export const generateImage = async (prompt: string, aspectRatio: string = '1:1', referenceImages?: { data: string; mimeType: string }[]): Promise<{ images: string[], model: string }> => {
    const ai = getGeminiClient();
    const ratioMap: Record<string, string> = { '1:1': '1:1', '16:9': '16:9', '9:16': '9:16', '4:3': '4:3', '3:4': '3:4' };
    const validRatio = ratioMap[aspectRatio] || '1:1';

    // Simplify prompt to avoid confusing the model, ensure it knows context if refs exist
    let finalPrompt = prompt;
    if (referenceImages && referenceImages.length > 0) {
        finalPrompt = `Use the provided image(s) as reference. ${prompt}`;
    }

    try {
        const parts: any[] = [];
        if (referenceImages && referenceImages.length > 0) {
            referenceImages.forEach(img => {
                parts.push({ inlineData: { data: img.data, mimeType: img.mimeType } });
            });
        }
        parts.push({ text: finalPrompt });

        // Using gemini-2.5-flash-image (Nanobanana)
        // Configuration must strictly follow guidelines: no responseMimeType/responseSchema.
        // Aspect Ratio is supported in imageConfig.
        const response = await withRetry<GenerateContentResponse>(() => ai.models.generateContent({
            model: IMAGE_MODEL,
            contents: { parts },
            config: {
                imageConfig: { aspectRatio: validRatio as any }
            }
        }));

        const images: string[] = [];
        if (response.candidates?.[0]?.content?.parts) {
            for (const part of response.candidates[0].content.parts) {
                if (part.inlineData && part.inlineData.data) {
                    images.push(part.inlineData.data);
                }
            }
        }

        if (images.length > 0) {
            return { images, model: 'Gemini 2.5 Flash Image' };
        }

        // If no images found but no error thrown
        throw new Error("La IA respondió pero no generó datos de imagen.");

    } catch (error) {
        // Detailed error logging for debugging 2.5 Flash issues
        console.error("Gemini 2.5 Flash Image Generation Error:", error);
        handleGenerationError(error, 'imagen (Gemini 2.5)');
        return { images: [], model: '' }; // unreachable due to throw in handler
    }
};

export const editImage = async (images: { data: string; mimeType: string }[], prompt: string, aspectRatio: string = '1:1'): Promise<{ image?: { data: string; mimeType: string }, text?: string, model: string }> => {
    // Re-use generateImage for editing as Flash-Image supports both
    return await generateImage(prompt, aspectRatio, images).then(res => ({
        image: { data: res.images[0], mimeType: 'image/jpeg' },
